 unsigned char * border_orig = orig ;
 unsigned char * border_recon = recon ;
 for ( border_row = 0 ;
 border_row < 16 ;
 border_row ++ ) {
 for ( border_col = col ;
 border_col < cols ;
 border_col ++ ) {
 diff = border_orig [ border_col ] - border_recon [ border_col ] ;
 total_sse += diff * diff ;
 }
 border_orig += orig_stride ;
 border_recon += recon_stride ;
 }
 }
 orig += orig_stride * 16 ;
 recon += recon_stride * 16 ;
 }
