 row < rows ;
 row ++ ) {
 for ( col = 0 ;
 col < cols ;
 col ++ ) {
 diff = orig [ col ] - recon [ col ] ;
 total_sse += diff * diff ;
 }
 orig += orig_stride ;
 recon += recon_stride ;
 }
