 # if defined ( _WIN32 ) && ! defined ( __CYGWIN__ ) if ( mtime - now > 365 * 86400 / 2 || mtime - now < - 365 * 86400 / 2 ) fmt = cpio -> day_first ? "%d %b %Y" : "%b %d %Y" ;
