 }
 if ( length == 0 ) {
 if ( code == 1 ) {
 length = bytestream2_get_byte ( & g ) ;
 offset = bytestream2_get_le16 ( & g ) ;
 }
 else {
 length = bytestream2_get_le16 ( & g ) ;
 if ( code == 2 && length == 0 ) break ;
 }
 }
