 break ;
 case 2 : dst += length ;
 break ;
 case 3 : colour1 = bytestream2_get_byte ( & g ) ;
 colour2 = bytestream2_get_byte ( & g ) ;
 while ( length -- ) {
 * dst ++ = colour1 ;
 * dst ++ = colour2 ;
 }
