 const char * fmt ;
 char * pfname = ( char * ) gs_alloc_bytes ( dev -> memory , gp_file_name_sizeof , "gx_device_open_output_file(pfname)" ) ;
 int code ;
 if ( pfname == NULL ) {
 code = gs_note_error ( gs_error_VMerror ) ;
 goto done ;
 }
 if ( strlen ( fname ) == 0 ) {
 code = gs_note_error ( gs_error_undefinedfilename ) ;
