 uint_fast32_t cblkno ;
 if ( prc -> cblks ) {
 for ( cblkno = 0 , cblk = prc -> cblks ;
 cblkno < prc -> numcblks ;
 ++ cblkno , ++ cblk ) {
 cblk_destroy ( cblk ) ;
 }
 jas_free ( prc -> cblks ) ;
 prc -> cblks = NULL ;
 }
 if ( prc -> incltree ) {
