 time_low = pletoh16 ( & frame2 . time_low ) ;
 time_med = pletoh16 ( & frame2 . time_med ) ;
 time_high = frame2 . time_high ;
 time_day = frame2 . time_day ;
 size = pletoh16 ( & frame2 . size ) ;
 true_size = pletoh16 ( & frame2 . true_size ) ;
 length -= sizeof frame2 ;
