 v = ( ( v & 0x7F ) ^ sign ) - sign ;
 v += 0x80 ;
 }
 memset ( b -> cur_dec , v , t ) ;
 b -> cur_dec += t ;
 }
 else {
 while ( b -> cur_dec < dec_end ) {
 c -> col_lastval = GET_HUFF ( gb , c -> col_high [ c -> col_lastval ] ) ;
 v = GET_HUFF ( gb , b -> tree ) ;
 v = ( c -> col_lastval << 4 ) | v ;
 if ( c -> version < 'i' ) {
 sign = ( ( int8_t ) v ) >> 7 ;
 v = ( ( v & 0x7F ) ^ sign ) - sign ;
