static void fill_label_bitfield64 ( field_info * fi , gchar * label_str , gboolean is_signed ) {
 char * p ;
 int bitfield_byte_length , bitwidth ;
 guint64 unshifted_value ;
 guint64 value ;
 char buf [ 48 ] ;
 const char * out ;
 header_field_info * hfinfo = fi -> hfinfo ;
 bitwidth = hfinfo_container_bitwidth ( hfinfo ) ;
 if ( is_signed ) value = fvalue_get_sinteger64 ( & fi -> value ) ;
 else value = fvalue_get_uinteger64 ( & fi -> value ) ;
 unshifted_value = value ;
 if ( hfinfo -> bitmask ) {
 unshifted_value <<= hfinfo_bitshift ( hfinfo ) ;
 }
 p = decode_bitfield_value ( label_str , unshifted_value , hfinfo -> bitmask , bitwidth ) ;
 bitfield_byte_length = ( int ) ( p - label_str ) ;
 if ( hfinfo -> display == BASE_CUSTOM ) {
 gchar tmp [ ITEM_LABEL_LENGTH ] ;
 const custom_fmt_func_64_t fmtfunc64 = ( const custom_fmt_func_64_t ) hfinfo -> strings ;
 DISSECTOR_ASSERT ( fmtfunc64 ) ;
 fmtfunc64 ( tmp , value ) ;
 label_fill ( label_str , bitfield_byte_length , hfinfo , tmp ) ;
 }
 else if ( hfinfo -> strings ) {
 const char * val_str = hf_try_val64_to_str_const ( value , hfinfo , "Unknown" ) ;
 out = hfinfo_number_vals_format64 ( hfinfo , buf , value ) ;
 if ( out == NULL ) label_fill ( label_str , bitfield_byte_length , hfinfo , val_str ) ;
 else label_fill_descr ( label_str , bitfield_byte_length , hfinfo , val_str , out ) ;
 }
 else {
 out = hfinfo_number_value_format64 ( hfinfo , buf , value ) ;
 label_fill ( label_str , bitfield_byte_length , hfinfo , out ) ;
 }
 }

static int v410_decode_frame ( AVCodecContext * avctx , void * data , int * got_frame , AVPacket * avpkt ) {
 AVFrame * pic = data ;
 uint8_t * src = avpkt -> data ;
 uint16_t * y , * u , * v ;
 uint32_t val ;
 int i , j ;
 if ( avpkt -> size < 4 * avctx -> height * avctx -> width ) {
 av_log ( avctx , AV_LOG_ERROR , "Insufficient input data.\n" ) ;
 return AVERROR ( EINVAL ) ;
 }
 if ( ff_get_buffer ( avctx , pic , 0 ) < 0 ) {
 av_log ( avctx , AV_LOG_ERROR , "Could not allocate buffer.\n" ) ;
 return AVERROR ( ENOMEM ) ;
 }
 pic -> key_frame = 1 ;
 pic -> pict_type = AV_PICTURE_TYPE_I ;
 y = ( uint16_t * ) pic -> data [ 0 ] ;
 u = ( uint16_t * ) pic -> data [ 1 ] ;
 v = ( uint16_t * ) pic -> data [ 2 ] ;
 for ( i = 0 ;
 i < avctx -> height ;
 i ++ ) {
 for ( j = 0 ;
 j < avctx -> width ;
 j ++ ) {
 val = AV_RL32 ( src ) ;
 u [ j ] = ( val >> 2 ) & 0x3FF ;
 y [ j ] = ( val >> 12 ) & 0x3FF ;
 v [ j ] = ( val >> 22 ) ;
 src += 4 ;
 }
 y += pic -> linesize [ 0 ] >> 1 ;
 u += pic -> linesize [ 1 ] >> 1 ;
 v += pic -> linesize [ 2 ] >> 1 ;
 }
 * got_frame = 1 ;
 return avpkt -> size ;
 }

static void cirrus_vga_write_cr ( CirrusVGAState * s , int reg_value ) {
 switch ( s -> vga . cr_index ) {
 case 0x00 : case 0x01 : case 0x02 : case 0x03 : case 0x04 : case 0x05 : case 0x06 : case 0x07 : case 0x08 : case 0x09 : case 0x0a : case 0x0b : case 0x0c : case 0x0d : case 0x0e : case 0x0f : case 0x10 : case 0x11 : case 0x12 : case 0x13 : case 0x14 : case 0x15 : case 0x16 : case 0x17 : case 0x18 : if ( ( s -> vga . cr [ 0x11 ] & 0x80 ) && s -> vga . cr_index <= 7 ) {
 if ( s -> vga . cr_index == 7 ) s -> vga . cr [ 7 ] = ( s -> vga . cr [ 7 ] & ~ 0x10 ) | ( reg_value & 0x10 ) ;
 return ;
 }
 s -> vga . cr [ s -> vga . cr_index ] = reg_value ;
 switch ( s -> vga . cr_index ) {
 case 0x00 : case 0x04 : case 0x05 : case 0x06 : case 0x07 : case 0x11 : case 0x17 : s -> vga . update_retrace_info ( & s -> vga ) ;
 break ;
 }
 break ;
 case 0x19 : case 0x1a : case 0x1b : case 0x1c : case 0x1d : s -> vga . cr [ s -> vga . cr_index ] = reg_value ;
 # ifdef DEBUG_CIRRUS printf ( "cirrus: handled outport cr_index %02x, cr_value %02x\n" , s -> vga . cr_index , reg_value ) ;
 # endif break ;
 case 0x22 : case 0x24 : case 0x26 : case 0x27 : break ;
 case 0x25 : default : # ifdef DEBUG_CIRRUS printf ( "cirrus: outport cr_index %02x, cr_value %02x\n" , s -> vga . cr_index , reg_value ) ;
 # endif break ;
 }
 }

