 }
 }
 else {
 while ( length -- ) {
 if ( n == 0 ) aes_crypt_ecb ( ctx , AES_ENCRYPT , iv , iv ) ;
 iv [ n ] = * output ++ = ( unsigned char ) ( iv [ n ] ^ * input ++ ) ;
 n = ( n + 1 ) & 0x0F ;
 }
 }
 * iv_off = n ;
 }

