 }
 s -> pixel_ptr += s -> stride * 2 ;
 }
 }
 }
 else {
 uint64_t flags ;
 flags = bytestream2_get_le64 ( & s -> stream_ptr ) ;
 if ( P [ 2 ] <= P [ 3 ] ) {
 for ( y = 0 ;
 y < 8 ;
 y ++ ) {
 for ( x = 0 ;
 x < 8 ;
 x += 2 , flags >>= 2 ) {
 s -> pixel_ptr [ x ] = s -> pixel_ptr [ x + 1 ] = P [ flags & 0x03 ] ;
 }
