 }
 }
 while ( tok != PDF_TOK_EOF ) ;
 }
 fz_always ( ctx ) {
 pdf_clear_stack ( ctx , csi ) ;
 }
 fz_catch ( ctx ) {
 int caught = fz_caught ( ctx ) ;
 if ( cookie ) {
 if ( caught == FZ_ERROR_TRYLATER ) {
 if ( cookie -> incomplete_ok ) cookie -> incomplete ++ ;
