 map = table -> reverseMap ;
 count = table -> mappingsLength ;
 m = mappings ;
 for ( i = j = 0 ;
 i < count ;
 ++ m , ++ i ) {
 flag = m -> f ;
 if ( flag >= 0 ) {
 flag &= MBCS_FROM_U_EXT_MASK ;
 m -> f = flag ;
 }
 if ( flag == 0 || flag == 1 || ( flag == 2 && m -> bLen == 1 ) || flag == 4 ) {
