 if ( m -> uLen > 1 ) {
 UChar32 * u32 ;
 UChar * u ;
 UChar32 c ;
 int32_t q , r ;
 u32 = UCM_GET_CODE_POINTS ( table , m ) ;
 u = ( UChar * ) u32 ;
 for ( r = 2 , q = 1 ;
 q < m -> uLen ;
 ++ q ) {
