 repoint_table_dependencies ( AH ) ;
 if ( AH -> version < K_VERS_1_11 ) {
 for ( te = AH -> toc -> next ;
 te != AH -> toc ;
 te = te -> next ) {
 if ( strcmp ( te -> desc , "BLOB COMMENTS" ) == 0 && te -> nDeps == 0 ) {
 TocEntry * te2 ;
 for ( te2 = AH -> toc -> next ;
 te2 != AH -> toc ;
 te2 = te2 -> next ) {
 if ( strcmp ( te2 -> desc , "BLOBS" ) == 0 ) {
