 te -> nRevDeps = 0 ;
 }
 for ( te = AH -> toc -> next ;
 te != AH -> toc ;
 te = te -> next ) {
 for ( i = 0 ;
 i < te -> nDeps ;
 i ++ ) {
 DumpId depid = te -> dependencies [ i ] ;
 if ( depid <= AH -> maxDumpId && AH -> tocsByDumpId [ depid ] != NULL ) {
