 tl = dc_cache [ TOP_LEFT ] ;
 t = dc_cache [ TOP ] ;
 if ( FFABS ( t - tl ) <= FFABS ( l - tl ) ) dc += l ;
 else dc += t ;
 }
 else {
 dc += dc_cache [ TOP ] ;
 }
 }
 else if ( bx ) {
 dc += dc_cache [ LEFT ] ;
 }
 dc_cache [ LEFT ] = dc ;
 block [ 0 ] = dc * quant_mat [ 0 ] ;
 while ( pos < 64 ) {
 val = get_vlc2 ( gb , ac_vlc -> table , 9 , 2 ) ;
