 last = * src ++ ;
 ybuf [ 0 ] = last << 1 ;
 for ( j = 1 ;
 j < avctx -> width - 1 ;
 j += 2 ) {
 cur = ( last + * src ++ ) & 0x1F ;
 ybuf [ j ] = last + cur ;
 ybuf [ j + 1 ] = cur << 1 ;
 last = cur ;
 }
 ybuf [ j ] = last << 1 ;
 prev_buf = ybuf ;
 ybuf += avctx -> width ;
 for ( i = 1 ;
 i < avctx -> height ;
 i ++ ) {
 last = ( ( prev_buf [ 0 ] >> 1 ) + * src ++ ) & 0x1F ;
 ybuf [ 0 ] = last << 1 ;
 for ( j = 1 ;
 j < avctx -> width - 1 ;
 j += 2 ) {
 cur = ( ( prev_buf [ j + 1 ] >> 1 ) + * src ++ ) & 0x1F ;
 ybuf [ j ] = last + cur ;
 ybuf [ j + 1 ] = cur << 1 ;
 last = cur ;
 }
 ybuf [ j ] = last << 1 ;
 prev_buf = ybuf ;
 ybuf += avctx -> width ;
 }
 if ( corr_off ) {
 int dec_size ;
 bytestream2_seek ( & s -> gb , 8 + corr_off , SEEK_SET ) ;
