 if ( dec_size < 0 ) dec_size = 0 ;
 for ( i = 0 ;
 i < dec_size ;
 i ++ ) s -> y_buffer [ i * 2 + 1 ] = ( s -> y_buffer [ i * 2 + 1 ] + ( s -> scratch_buffer [ i ] << 1 ) ) & 0x3F ;
