 cur_offset += 4 ;
 rr_len -= 4 ;
 proto_tree_add_item ( rr_tree , hf_dns_wins_lookup_timeout , tvb , cur_offset , 4 , ENC_BIG_ENDIAN ) ;
 cur_offset += 4 ;
 rr_len -= 4 ;
