int ff_mpeg4_decode_video_packet_header ( MpegEncContext * s ) {
 int mb_num_bits = av_log2 ( s -> mb_num - 1 ) + 1 ;
 int header_extension = 0 , mb_num , len ;
 if ( get_bits_count ( & s -> gb ) > s -> gb . size_in_bits - 20 ) return - 1 ;
 for ( len = 0 ;
 len < 32 ;
 len ++ ) {
 if ( get_bits1 ( & s -> gb ) ) break ;
 }
 if ( len != ff_mpeg4_get_video_packet_prefix_length ( s ) ) {
 av_log ( s -> avctx , AV_LOG_ERROR , "marker does not match f_code\n" ) ;
 return - 1 ;
 }
 if ( s -> shape != RECT_SHAPE ) {
 header_extension = get_bits1 ( & s -> gb ) ;
 }
 mb_num = get_bits ( & s -> gb , mb_num_bits ) ;
 if ( mb_num >= s -> mb_num ) {
 av_log ( s -> avctx , AV_LOG_ERROR , "illegal mb_num in video packet (%d %d) \n" , mb_num , s -> mb_num ) ;
 return - 1 ;
 }
 if ( s -> pict_type == AV_PICTURE_TYPE_B ) {
 int mb_x = 0 , mb_y = 0 ;
 while ( s -> next_picture . mbskip_table [ s -> mb_index2xy [ mb_num ] ] ) {
 if ( ! mb_x ) ff_thread_await_progress ( & s -> next_picture_ptr -> tf , mb_y ++ , 0 ) ;
 mb_num ++ ;
 if ( ++ mb_x == s -> mb_width ) mb_x = 0 ;
 }
 if ( mb_num >= s -> mb_num ) return - 1 ;
 }
 s -> mb_x = mb_num % s -> mb_width ;
 s -> mb_y = mb_num / s -> mb_width ;
 if ( s -> shape != BIN_ONLY_SHAPE ) {
 int qscale = get_bits ( & s -> gb , s -> quant_precision ) ;
 if ( qscale ) s -> chroma_qscale = s -> qscale = qscale ;
 }
 if ( s -> shape == RECT_SHAPE ) {
 header_extension = get_bits1 ( & s -> gb ) ;
 }
 if ( header_extension ) {
 int time_incr = 0 ;
 while ( get_bits1 ( & s -> gb ) != 0 ) time_incr ++ ;
 check_marker ( & s -> gb , "before time_increment in video packed header" ) ;
 skip_bits ( & s -> gb , s -> time_increment_bits ) ;
 check_marker ( & s -> gb , "before vop_coding_type in video packed header" ) ;
 skip_bits ( & s -> gb , 2 ) ;
 if ( s -> shape != BIN_ONLY_SHAPE ) {
 skip_bits ( & s -> gb , 3 ) ;
 if ( s -> pict_type == AV_PICTURE_TYPE_S && s -> vol_sprite_usage == GMC_SPRITE ) {
 mpeg4_decode_sprite_trajectory ( s , & s -> gb ) ;
 av_log ( s -> avctx , AV_LOG_ERROR , "untested\n" ) ;
 }
 if ( s -> pict_type != AV_PICTURE_TYPE_I ) {
 int f_code = get_bits ( & s -> gb , 3 ) ;
 if ( f_code == 0 ) {
 av_log ( s -> avctx , AV_LOG_ERROR , "Error, video packet header damaged (f_code=0)\n" ) ;
 }
 }
 if ( s -> pict_type == AV_PICTURE_TYPE_B ) {
 int b_code = get_bits ( & s -> gb , 3 ) ;
 if ( b_code == 0 ) {
 av_log ( s -> avctx , AV_LOG_ERROR , "Error, video packet header damaged (b_code=0)\n" ) ;
 }
 }
 }
 }
 return 0 ;
 }

static vpx_codec_err_t ctrl_set_svc ( vpx_codec_alg_priv_t * ctx , va_list args ) {
 int data = va_arg ( args , int ) ;
 const vpx_codec_enc_cfg_t * cfg = & ctx -> cfg ;
 vp9_set_svc ( ctx -> cpi , data ) ;
 if ( data == 1 && ( cfg -> rc_end_usage == VPX_CBR || cfg -> g_pass == VPX_RC_FIRST_PASS || cfg -> g_pass == VPX_RC_LAST_PASS ) && cfg -> ss_number_layers > 1 && cfg -> ts_number_layers > 1 ) {
 return VPX_CODEC_INVALID_PARAM ;
 }
 return VPX_CODEC_OK ;
 }

int phar_is_tar ( char * buf , char * fname ) {
 tar_header * header = ( tar_header * ) buf ;
 php_uint32 checksum = phar_tar_number ( header -> checksum , sizeof ( header -> checksum ) ) ;
 php_uint32 ret ;
 char save [ sizeof ( header -> checksum ) ] ;
 if ( ! strncmp ( buf , "<?php" , sizeof ( "<?php" ) - 1 ) ) {
 return 0 ;
 }
 memcpy ( save , header -> checksum , sizeof ( header -> checksum ) ) ;
 memset ( header -> checksum , ' ' , sizeof ( header -> checksum ) ) ;
 ret = ( checksum == phar_tar_checksum ( buf , 512 ) ) ;
 memcpy ( header -> checksum , save , sizeof ( header -> checksum ) ) ;
 if ( ! ret && strstr ( fname , ".tar" ) ) {
 return 1 ;
 }
 return ret ;
 }

