uint16_fract_t lut_inverse_interp16 ( uint16_t Value , uint16_t LutTable [ ] , int length , int NumZeroes , int NumPoles ) {
 int l = 1 ;
 int r = 0x10000 ;
 int x = 0 , res ;
 int cell0 , cell1 ;
 double val2 ;
 double y0 , y1 , x0 , x1 ;
 double a , b , f ;
 if ( NumZeroes == 0 && Value == 0 ) return 0 ;
