static EC_GROUP * ec_asn1_parameters2group ( const ECPARAMETERS * params ) {
 int ok = 0 , tmp ;
 EC_GROUP * ret = NULL ;
 BIGNUM * p = NULL , * a = NULL , * b = NULL ;
 EC_POINT * point = NULL ;
 long field_bits ;
 if ( ! params -> fieldID || ! params -> fieldID -> fieldType || ! params -> fieldID -> p . ptr ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 if ( ! params -> curve || ! params -> curve -> a || ! params -> curve -> a -> data || ! params -> curve -> b || ! params -> curve -> b -> data ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 a = BN_bin2bn ( params -> curve -> a -> data , params -> curve -> a -> length , NULL ) ;
 if ( a == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_BN_LIB ) ;
 goto err ;
 }
 b = BN_bin2bn ( params -> curve -> b -> data , params -> curve -> b -> length , NULL ) ;
 if ( b == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_BN_LIB ) ;
 goto err ;
 }
 tmp = OBJ_obj2nid ( params -> fieldID -> fieldType ) ;
 if ( tmp == NID_X9_62_characteristic_two_field ) {
 X9_62_CHARACTERISTIC_TWO * char_two ;
 char_two = params -> fieldID -> p . char_two ;
 field_bits = char_two -> m ;
 if ( field_bits > OPENSSL_ECC_MAX_FIELD_BITS ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_FIELD_TOO_LARGE ) ;
 goto err ;
 }
 if ( ( p = BN_new ( ) ) == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_MALLOC_FAILURE ) ;
 goto err ;
 }
 tmp = OBJ_obj2nid ( char_two -> type ) ;
 if ( tmp == NID_X9_62_tpBasis ) {
 long tmp_long ;
 if ( ! char_two -> p . tpBasis ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 tmp_long = ASN1_INTEGER_get ( char_two -> p . tpBasis ) ;
 if ( ! ( char_two -> m > tmp_long && tmp_long > 0 ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_TRINOMIAL_BASIS ) ;
 goto err ;
 }
 if ( ! BN_set_bit ( p , ( int ) char_two -> m ) ) goto err ;
 if ( ! BN_set_bit ( p , ( int ) tmp_long ) ) goto err ;
 if ( ! BN_set_bit ( p , 0 ) ) goto err ;
 }
 else if ( tmp == NID_X9_62_ppBasis ) {
 X9_62_PENTANOMIAL * penta ;
 penta = char_two -> p . ppBasis ;
 if ( ! penta ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 if ( ! ( char_two -> m > penta -> k3 && penta -> k3 > penta -> k2 && penta -> k2 > penta -> k1 && penta -> k1 > 0 ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_PENTANOMIAL_BASIS ) ;
 goto err ;
 }
 if ( ! BN_set_bit ( p , ( int ) char_two -> m ) ) goto err ;
 if ( ! BN_set_bit ( p , ( int ) penta -> k1 ) ) goto err ;
 if ( ! BN_set_bit ( p , ( int ) penta -> k2 ) ) goto err ;
 if ( ! BN_set_bit ( p , ( int ) penta -> k3 ) ) goto err ;
 if ( ! BN_set_bit ( p , 0 ) ) goto err ;
 }
 else if ( tmp == NID_X9_62_onBasis ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_NOT_IMPLEMENTED ) ;
 goto err ;
 }
 else {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 ret = EC_GROUP_new_curve_GF2m ( p , a , b , NULL ) ;
 }
 else if ( tmp == NID_X9_62_prime_field ) {
 if ( ! params -> fieldID -> p . prime ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 p = ASN1_INTEGER_to_BN ( params -> fieldID -> p . prime , NULL ) ;
 if ( p == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_ASN1_LIB ) ;
 goto err ;
 }
 if ( BN_is_negative ( p ) || BN_is_zero ( p ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_FIELD ) ;
 goto err ;
 }
 field_bits = BN_num_bits ( p ) ;
 if ( field_bits > OPENSSL_ECC_MAX_FIELD_BITS ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_FIELD_TOO_LARGE ) ;
 goto err ;
 }
 ret = EC_GROUP_new_curve_GFp ( p , a , b , NULL ) ;
 }
 else {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_FIELD ) ;
 goto err ;
 }
 if ( ret == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_EC_LIB ) ;
 goto err ;
 }
 if ( params -> curve -> seed != NULL ) {
 if ( ret -> seed != NULL ) OPENSSL_free ( ret -> seed ) ;
 if ( ! ( ret -> seed = OPENSSL_malloc ( params -> curve -> seed -> length ) ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_MALLOC_FAILURE ) ;
 goto err ;
 }
 memcpy ( ret -> seed , params -> curve -> seed -> data , params -> curve -> seed -> length ) ;
 ret -> seed_len = params -> curve -> seed -> length ;
 }
 if ( ! params -> order || ! params -> base || ! params -> base -> data ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_ASN1_ERROR ) ;
 goto err ;
 }
 if ( ( point = EC_POINT_new ( ret ) ) == NULL ) goto err ;
 EC_GROUP_set_point_conversion_form ( ret , ( point_conversion_form_t ) ( params -> base -> data [ 0 ] & ~ 0x01 ) ) ;
 if ( ! EC_POINT_oct2point ( ret , point , params -> base -> data , params -> base -> length , NULL ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_EC_LIB ) ;
 goto err ;
 }
 if ( ( a = ASN1_INTEGER_to_BN ( params -> order , a ) ) == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_ASN1_LIB ) ;
 goto err ;
 }
 if ( BN_is_negative ( a ) || BN_is_zero ( a ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_GROUP_ORDER ) ;
 goto err ;
 }
 if ( BN_num_bits ( a ) > ( int ) field_bits + 1 ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , EC_R_INVALID_GROUP_ORDER ) ;
 goto err ;
 }
 if ( params -> cofactor == NULL ) {
 if ( b ) {
 BN_free ( b ) ;
 b = NULL ;
 }
 }
 else if ( ( b = ASN1_INTEGER_to_BN ( params -> cofactor , b ) ) == NULL ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_ASN1_LIB ) ;
 goto err ;
 }
 if ( ! EC_GROUP_set_generator ( ret , point , a , b ) ) {
 ECerr ( EC_F_EC_ASN1_PARAMETERS2GROUP , ERR_R_EC_LIB ) ;
 goto err ;
 }
 ok = 1 ;
 err : if ( ! ok ) {
 if ( ret ) EC_GROUP_clear_free ( ret ) ;
 ret = NULL ;
 }
 if ( p ) BN_free ( p ) ;
 if ( a ) BN_free ( a ) ;
 if ( b ) BN_free ( b ) ;
 if ( point ) EC_POINT_free ( point ) ;
 return ( ret ) ;
 }

static int rm_assemble_video_frame ( AVFormatContext * s , AVIOContext * pb , RMDemuxContext * rm , RMStream * vst , AVPacket * pkt , int len , int * pseq , int64_t * timestamp ) {
 int hdr ;
 int seq = 0 , pic_num = 0 , len2 = 0 , pos = 0 ;
 int type ;
 int ret ;
 hdr = avio_r8 ( pb ) ;
 len -- ;
 type = hdr >> 6 ;
 if ( type != 3 ) {
 seq = avio_r8 ( pb ) ;
 len -- ;
 }
 if ( type != 1 ) {
 len2 = get_num ( pb , & len ) ;
 pos = get_num ( pb , & len ) ;
 pic_num = avio_r8 ( pb ) ;
 len -- ;
 }
 if ( len < 0 ) {
 av_log ( s , AV_LOG_ERROR , "Insufficient data\n" ) ;
 return - 1 ;
 }
 rm -> remaining_len = len ;
 if ( type & 1 ) {
 if ( type == 3 ) {
 len = len2 ;
 * timestamp = pos ;
 }
 if ( rm -> remaining_len < len ) {
 av_log ( s , AV_LOG_ERROR , "Insufficient remaining len\n" ) ;
 return - 1 ;
 }
 rm -> remaining_len -= len ;
 if ( av_new_packet ( pkt , len + 9 ) < 0 ) return AVERROR ( EIO ) ;
 pkt -> data [ 0 ] = 0 ;
 AV_WL32 ( pkt -> data + 1 , 1 ) ;
 AV_WL32 ( pkt -> data + 5 , 0 ) ;
 if ( ( ret = avio_read ( pb , pkt -> data + 9 , len ) ) != len ) {
 av_packet_unref ( pkt ) ;
 av_log ( s , AV_LOG_ERROR , "Failed to read %d bytes\n" , len ) ;
 return ret < 0 ? ret : AVERROR ( EIO ) ;
 }
 return 0 ;
 }
 / ow we have to deal with single slice * pseq = seq ;
 if ( ( seq & 0x7F ) == 1 || vst -> curpic_num != pic_num ) {
 if ( len2 > ffio_limit ( pb , len2 ) ) {
 av_log ( s , AV_LOG_ERROR , "Impossibly sized packet\n" ) ;
 return AVERROR_INVALIDDATA ;
 }
 vst -> slices = ( ( hdr & 0x3F ) << 1 ) + 1 ;
 vst -> videobufsize = len2 + 8 * vst -> slices + 1 ;
 av_packet_unref ( & vst -> pkt ) ;
 if ( av_new_packet ( & vst -> pkt , vst -> videobufsize ) < 0 ) return AVERROR ( ENOMEM ) ;
 memset ( vst -> pkt . data , 0 , vst -> pkt . size ) ;
 vst -> videobufpos = 8 * vst -> slices + 1 ;
 vst -> cur_slice = 0 ;
 vst -> curpic_num = pic_num ;
 vst -> pktpos = avio_tell ( pb ) ;
 }
 if ( type == 2 ) len = FFMIN ( len , pos ) ;
 if ( ++ vst -> cur_slice > vst -> slices ) {
 av_log ( s , AV_LOG_ERROR , "cur slice %d, too large\n" , vst -> cur_slice ) ;
 return 1 ;
 }
 if ( ! vst -> pkt . data ) return AVERROR ( ENOMEM ) ;
 AV_WL32 ( vst -> pkt . data - 7 + 8 * vst -> cur_slice , 1 ) ;
 AV_WL32 ( vst -> pkt . data - 3 + 8 * vst -> cur_slice , vst -> videobufpos - 8 * vst -> slices - 1 ) ;
 if ( vst -> videobufpos + len > vst -> videobufsize ) {
 av_log ( s , AV_LOG_ERROR , "outside videobufsize\n" ) ;
 return 1 ;
 }
 if ( avio_read ( pb , vst -> pkt . data + vst -> videobufpos , len ) != len ) return AVERROR ( EIO ) ;
 vst -> videobufpos += len ;
 rm -> remaining_len -= len ;
 if ( type == 2 || vst -> videobufpos == vst -> videobufsize ) {
 vst -> pkt . data [ 0 ] = vst -> cur_slice - 1 ;
 * pkt = vst -> pkt ;
 vst -> pkt . data = NULL ;
 vst -> pkt . size = 0 ;
 vst -> pkt . buf = NULL ;
 if ( vst -> slices != vst -> cur_slice ) memmove ( pkt -> data + 1 + 8 * vst -> cur_slice , pkt -> data + 1 + 8 * vst -> slices , vst -> videobufpos - 1 - 8 * vst -> slices ) ;
 pkt -> size = vst -> videobufpos + 8 * ( vst -> cur_slice - vst -> slices ) ;
 pkt -> pts = AV_NOPTS_VALUE ;
 pkt -> pos = vst -> pktpos ;
 vst -> slices = 0 ;
 return 0 ;
 }
 return 1 ;
 }

static int kvm_put_fpu ( X86CPU * cpu ) {
 CPUX86State * env = & cpu -> env ;
 struct kvm_fpu fpu ;
 int i ;
 memset ( & fpu , 0 , sizeof fpu ) ;
 fpu . fsw = env -> fpus & ~ ( 7 << 11 ) ;
 fpu . fsw |= ( env -> fpstt & 7 ) << 11 ;
 fpu . fcw = env -> fpuc ;
 fpu . last_opcode = env -> fpop ;
 fpu . last_ip = env -> fpip ;
 fpu . last_dp = env -> fpdp ;
 for ( i = 0 ;
 i < 8 ;
 ++ i ) {
 fpu . ftwx |= ( ! env -> fptags [ i ] ) << i ;
 }
 memcpy ( fpu . fpr , env -> fpregs , sizeof env -> fpregs ) ;
 for ( i = 0 ;
 i < CPU_NB_REGS ;
 i ++ ) {
 stq_p ( & fpu . xmm [ i ] [ 0 ] , env -> xmm_regs [ i ] . ZMM_Q ( 0 ) ) ;
 stq_p ( & fpu . xmm [ i ] [ 8 ] , env -> xmm_regs [ i ] . ZMM_Q ( 1 ) ) ;
 }
 fpu . mxcsr = env -> mxcsr ;
 return kvm_vcpu_ioctl ( CPU ( cpu ) , KVM_SET_FPU , & fpu ) ;
 }

ulong get_column_grant ( THD * thd , GRANT_INFO * grant , const char * db_name , const char * table_name , const char * field_name ) {
 GRANT_TABLE * grant_table ;
 GRANT_COLUMN * grant_column ;
 ulong priv ;
 rw_rdlock ( & LOCK_grant ) ;
 if ( grant -> version != grant_version ) {
 Security_context * sctx = thd -> security_ctx ;
 grant -> grant_table = table_hash_search ( sctx -> host , sctx -> ip , db_name , sctx -> priv_user , table_name , 0 ) ;
 grant -> version = grant_version ;
 }
 if ( ! ( grant_table = grant -> grant_table ) ) priv = grant -> privilege ;
 else {
 grant_column = column_hash_search ( grant_table , field_name , ( uint ) strlen ( field_name ) ) ;
 if ( ! grant_column ) priv = ( grant -> privilege | grant_table -> privs ) ;
 else priv = ( grant -> privilege | grant_table -> privs | grant_column -> rights ) ;
 }
 rw_unlock ( & LOCK_grant ) ;
 return priv ;
 }

static void ps2_mouse_event ( DeviceState * dev , QemuConsole * src , InputEvent * evt ) {
 static const int bmap [ INPUT_BUTTON__MAX ] = {
 [ INPUT_BUTTON_LEFT ] = PS2_MOUSE_BUTTON_LEFT , [ INPUT_BUTTON_MIDDLE ] = PS2_MOUSE_BUTTON_MIDDLE , [ INPUT_BUTTON_RIGHT ] = PS2_MOUSE_BUTTON_RIGHT , [ INPUT_BUTTON_SIDE ] = PS2_MOUSE_BUTTON_SIDE , [ INPUT_BUTTON_EXTRA ] = PS2_MOUSE_BUTTON_EXTRA , }
 ;
 PS2MouseState * s = ( PS2MouseState * ) dev ;
 InputMoveEvent * move ;
 InputBtnEvent * btn ;
 if ( ! ( s -> mouse_status & MOUSE_STATUS_ENABLED ) ) return ;
 switch ( evt -> type ) {
 case INPUT_EVENT_KIND_REL : move = evt -> u . rel . data ;
 if ( move -> axis == INPUT_AXIS_X ) {
 s -> mouse_dx += move -> value ;
 }
 else if ( move -> axis == INPUT_AXIS_Y ) {
 s -> mouse_dy -= move -> value ;
 }
 break ;
 case INPUT_EVENT_KIND_BTN : btn = evt -> u . btn . data ;
 if ( btn -> down ) {
 s -> mouse_buttons |= bmap [ btn -> button ] ;
 if ( btn -> button == INPUT_BUTTON_WHEEL_UP ) {
 s -> mouse_dz -- ;
 }
 else if ( btn -> button == INPUT_BUTTON_WHEEL_DOWN ) {
 s -> mouse_dz ++ ;
 }
 }
 else {
 s -> mouse_buttons &= ~ bmap [ btn -> button ] ;
 }
 break ;
 default : break ;
 }
 }

static void xhci_runtime_write ( void * ptr , hwaddr reg , uint64_t val , unsigned size ) {
 XHCIState * xhci = ptr ;
 int v = ( reg - 0x20 ) / 0x20 ;
 XHCIInterrupter * intr = & xhci -> intr [ v ] ;
 trace_usb_xhci_runtime_write ( reg , val ) ;
 if ( reg < 0x20 ) {
 trace_usb_xhci_unimplemented ( "runtime write" , reg ) ;
 return ;
 }
 switch ( reg & 0x1f ) {
 case 0x00 : if ( val & IMAN_IP ) {
 intr -> iman &= ~ IMAN_IP ;
 }
 intr -> iman &= ~ IMAN_IE ;
 intr -> iman |= val & IMAN_IE ;
 if ( v == 0 ) {
 xhci_intx_update ( xhci ) ;
 }
 xhci_msix_update ( xhci , v ) ;
 break ;
 case 0x04 : intr -> imod = val ;
 break ;
 case 0x08 : intr -> erstsz = val & 0xffff ;
 break ;
 case 0x10 : intr -> erstba_low = val & 0xfffffff0 ;
 break ;
 case 0x14 : intr -> erstba_high = val ;
 xhci_er_reset ( xhci , v ) ;
 break ;
 case 0x18 : if ( val & ERDP_EHB ) {
 intr -> erdp_low &= ~ ERDP_EHB ;
 }
 intr -> erdp_low = ( val & ~ ERDP_EHB ) | ( intr -> erdp_low & ERDP_EHB ) ;
 break ;
 case 0x1c : intr -> erdp_high = val ;
 xhci_events_update ( xhci , v ) ;
 break ;
 default : trace_usb_xhci_unimplemented ( "oper write" , reg ) ;
 }
 }

