 if ( need32 || want32 ) {
 if ( planar ) s -> avctx -> sample_fmt = AV_SAMPLE_FMT_S32P ;
 else s -> avctx -> sample_fmt = AV_SAMPLE_FMT_S32 ;
 s -> sample_shift = 32 - s -> bps ;
 }
 else {
 if ( planar ) s -> avctx -> sample_fmt = AV_SAMPLE_FMT_S16P ;
 else s -> avctx -> sample_fmt = AV_SAMPLE_FMT_S16 ;
