 reason = "Refused by certificate options" ;
 goto fail_reason ;
 }
 if ( principals_opts == NULL ) {
 final_opts = cert_opts ;
 cert_opts = NULL ;
 }
 else {
 if ( auth_authorise_keyopts ( ssh , pw , principals_opts , 0 , "principals" ) != 0 ) {
