 if ( authoptsp != NULL ) {
 * authoptsp = final_opts ;
 final_opts = NULL ;
 }
 ret = 1 ;
 out : sshauthopt_free ( principals_opts ) ;
 sshauthopt_free ( cert_opts ) ;
 sshauthopt_free ( final_opts ) ;
 free ( principals_file ) ;
 free ( ca_fp ) ;
 return ret ;
 }

