 unsigned char * tmp ;
 int extra = 0 ;
 unsigned int n ;
 if ( negative ) return gcry_error ( GPG_ERR_INTERNAL ) ;
 tmp = _gcry_mpi_get_buffer ( a , 0 , & n , NULL ) ;
