 gcry_free ( tmp ) ;
 return gcry_error ( GPG_ERR_TOO_SHORT ) ;
 }
 if ( buffer ) {
 unsigned char * s = buffer ;
 if ( extra ) * s ++ = 0 ;
 memcpy ( s , tmp , n - extra ) ;
 }
 gcry_free ( tmp ) ;
 * nwritten = n ;
