 }
 else if ( format == GCRYMPI_FMT_USG ) {
 unsigned int n = ( nbits + 7 ) / 8 ;
 if ( buffer && n > len ) return gcry_error ( GPG_ERR_TOO_SHORT ) ;
 if ( buffer ) {
 unsigned char * tmp ;
 tmp = _gcry_mpi_get_buffer ( a , 0 , & n , NULL ) ;
 if ( ! tmp ) return gpg_error_from_syserror ( ) ;
 memcpy ( buffer , tmp , n ) ;
 gcry_free ( tmp ) ;
 }
 * nwritten = n ;
