 has_palette = 1 ;
 break ;
 case 8 : case 40 : qtrle_decode_8bpp ( s , row_ptr , height ) ;
 has_palette = 1 ;
 break ;
 case 16 : qtrle_decode_16bpp ( s , row_ptr , height ) ;
 break ;
