static int selinux_parse_opts_str ( char * options , struct security_mnt_opts * opts ) {
 char * p ;
 char * context = NULL , * defcontext = NULL ;
 char * fscontext = NULL , * rootcontext = NULL ;
 int rc , num_mnt_opts = 0 ;
 opts -> num_mnt_opts = 0 ;
 while ( ( p = strsep ( & options , "|" ) ) != NULL ) {
 int token ;
 substring_t args [ MAX_OPT_ARGS ] ;
 if ( ! * p ) continue ;
 token = match_token ( p , tokens , args ) ;
 switch ( token ) {
 case Opt_context : if ( context || defcontext ) {
 rc = - EINVAL ;
 printk ( KERN_WARNING SEL_MOUNT_FAIL_MSG ) ;
 goto out_err ;
 }
 context = match_strdup ( & args [ 0 ] ) ;
 if ( ! context ) {
 rc = - ENOMEM ;
 goto out_err ;
 }
 break ;
 case Opt_fscontext : if ( fscontext ) {
 rc = - EINVAL ;
 printk ( KERN_WARNING SEL_MOUNT_FAIL_MSG ) ;
 goto out_err ;
 }
 fscontext = match_strdup ( & args [ 0 ] ) ;
 if ( ! fscontext ) {
 rc = - ENOMEM ;
 goto out_err ;
 }
 break ;
 case Opt_rootcontext : if ( rootcontext ) {
 rc = - EINVAL ;
 printk ( KERN_WARNING SEL_MOUNT_FAIL_MSG ) ;
 goto out_err ;
 }
 rootcontext = match_strdup ( & args [ 0 ] ) ;
 if ( ! rootcontext ) {
 rc = - ENOMEM ;
 goto out_err ;
 }
 break ;
 case Opt_defcontext : if ( context || defcontext ) {
 rc = - EINVAL ;
 printk ( KERN_WARNING SEL_MOUNT_FAIL_MSG ) ;
 goto out_err ;
 }
 defcontext = match_strdup ( & args [ 0 ] ) ;
 if ( ! defcontext ) {
 rc = - ENOMEM ;
 goto out_err ;
 }
 break ;
 case Opt_labelsupport : break ;
 default : rc = - EINVAL ;
 printk ( KERN_WARNING "SELinux: unknown mount option\n" ) ;
 goto out_err ;
 }
 }
 rc = - ENOMEM ;
 opts -> mnt_opts = kcalloc ( NUM_SEL_MNT_OPTS , sizeof ( char * ) , GFP_KERNEL ) ;
 if ( ! opts -> mnt_opts ) goto out_err ;
 opts -> mnt_opts_flags = kcalloc ( NUM_SEL_MNT_OPTS , sizeof ( int ) , GFP_KERNEL ) ;
 if ( ! opts -> mnt_opts_flags ) {
 kfree ( opts -> mnt_opts ) ;
 goto out_err ;
 }
 if ( fscontext ) {
 opts -> mnt_opts [ num_mnt_opts ] = fscontext ;
 opts -> mnt_opts_flags [ num_mnt_opts ++ ] = FSCONTEXT_MNT ;
 }
 if ( context ) {
 opts -> mnt_opts [ num_mnt_opts ] = context ;
 opts -> mnt_opts_flags [ num_mnt_opts ++ ] = CONTEXT_MNT ;
 }
 if ( rootcontext ) {
 opts -> mnt_opts [ num_mnt_opts ] = rootcontext ;
 opts -> mnt_opts_flags [ num_mnt_opts ++ ] = ROOTCONTEXT_MNT ;
 }
 if ( defcontext ) {
 opts -> mnt_opts [ num_mnt_opts ] = defcontext ;
 opts -> mnt_opts_flags [ num_mnt_opts ++ ] = DEFCONTEXT_MNT ;
 }
 opts -> num_mnt_opts = num_mnt_opts ;
 return 0 ;
 out_err : kfree ( context ) ;
 kfree ( defcontext ) ;
 kfree ( fscontext ) ;
 kfree ( rootcontext ) ;
 return rc ;
 }

