 ry = size_y ;
 if ( is_clockwise != is_large_arc ) sign = 1 ;
 else sign = - 1 ;
 fz_rotate ( & rotmat , rotation_angle ) ;
 fz_rotate ( & revmat , - rotation_angle ) ;
