 ry = fabsf ( ry ) ;
 if ( rx < 0.001f || ry < 0.001f || ( x1 == x2 && y1 == y2 ) ) {
 fz_lineto ( doc , path , x2 , y2 ) ;
 return ;
 }
 pt . x = ( x1 - x2 ) / 2 ;
 pt . y = ( y1 - y2 ) / 2 ;
 fz_transform_vector ( & pt , & revmat ) ;
 x1t = pt . x ;
 y1t = pt . y ;
 t1 = ( x1t * x1t ) / ( rx * rx ) + ( y1t * y1t ) / ( ry * ry ) ;
