 ry = ry * sqrtf ( t1 ) ;
 }
 t1 = ( rx * rx * ry * ry ) - ( rx * rx * y1t * y1t ) - ( ry * ry * x1t * x1t ) ;
 t2 = ( rx * rx * y1t * y1t ) + ( ry * ry * x1t * x1t ) ;
 t3 = t1 / t2 ;
 if ( t3 < 0 ) t3 = 0 ;
 t3 = sqrtf ( t3 ) ;
