 cyt = sign * t3 * - ( ry * x1t ) / rx ;
 pt . x = cxt ;
 pt . y = cyt ;
 fz_transform_vector ( & pt , & rotmat ) ;
 cx = pt . x + ( x1 + x2 ) / 2 ;
 cy = pt . y + ( y1 + y2 ) / 2 ;
 {
 fz_point coord1 , coord2 , coord3 , coord4 ;
 coord1 . x = 1 ;
 coord1 . y = 0 ;
 coord2 . x = ( x1t - cxt ) / rx ;
 coord2 . y = ( y1t - cyt ) / ry ;
 coord3 . x = ( x1t - cxt ) / rx ;
 coord3 . y = ( y1t - cyt ) / ry ;
 coord4 . x = ( - x1t - cxt ) / rx ;
 coord4 . y = ( - y1t - cyt ) / ry ;
 th1 = angle_between ( coord1 , coord2 ) ;
 dth = angle_between ( coord3 , coord4 ) ;
