 }
 # else int rdmult = 88 * q * q / 24 ;
 # endif if ( cpi -> oxcf . pass == 2 && ( cpi -> common . frame_type != KEY_FRAME ) ) {
 const GF_GROUP * const gf_group = & cpi -> twopass . gf_group ;
