 return NULL ;
 }
 get_current_time ( & timenow ) ;
 if ( s -> d1 -> next_timeout . tv_sec < timenow . tv_sec || ( s -> d1 -> next_timeout . tv_sec == timenow . tv_sec && s -> d1 -> next_timeout . tv_usec <= timenow . tv_usec ) ) {
