 if ( s -> param_presence_flags & PARAM_IIR ) if ( get_bits1 ( gbp ) ) if ( ( ret = read_filter_params ( m , gbp , substr , ch , IIR ) ) < 0 ) return ret ;
 if ( fir -> order + iir -> order > 8 ) {
