 break ;
 }
 }
 if ( resultStrLen == 1 ) {
 g_free ( tmpStr ) ;
 return ;
 }
 resultStr = ( gchar * ) g_malloc ( resultStrLen ) ;
 for ( i = 0 , j = 0 ;
 tmpStr [ i ] ;
 i ++ ) {
